// Extract Topic from Quiz Request
// Input: 'quiz photosynthesis' or 'quiz world war 2'
const text = $json.text || '';
const phone = $json.waId || $json.from || 'unknown';
const senderName = $json.senderName || 'Student';

const topic = text.replace(/^quiz\s+/i, '').trim();
if (!topic) throw new Error('No topic provided.');

const today = new Date().toISOString().split('T')[0];
const sessionKey = `${phone}_${today}`;

return { json: { phone, senderName, topic, sessionKey, today } };

// Format Quiz & Build WhatsApp Message
// Parses OpenAI response and formats quiz for WhatsApp display

const rawText = $json.output || '{}';

let quiz = {};
try {
  quiz = JSON.parse(rawText);
} catch (e) {
  const match = rawText.match(/\{[\s\S]*\}/);
  if (match) { try { quiz = JSON.parse(match[0]); } catch (e2) { quiz = {}; } }
}

const phone = $('Extract Topic').item.json.phone;
const senderName = $('Extract Topic').item.json.senderName;
const topic = $('Extract Topic').item.json.topic;
const sessionKey = $('Extract Topic').item.json.sessionKey;
const today = $('Extract Topic').item.json.today;
const questions = quiz.questions || [];

if (questions.length === 0) throw new Error('OpenAI did not return valid questions');

// Build WhatsApp quiz message
const lines = [
  `🎓 *Quiz Time, ${senderName}!*`,
  `📚 *Topic: ${topic.toUpperCase()}*`,
  '',
  'Reply with: *answer 1X 2X 3X*',
  'Example: *answer 1a 2c 3b*',
  '━━━━━━━━━━━━━━━━━━'
];

const correctAnswers = {};
for (const q of questions) {
  lines.push('');
  lines.push(`*Q${q.number}.* ${q.question}`);
  lines.push(`  🅐 ${q.options.a}`);
  lines.push(`  🅑 ${q.options.b}`);
  lines.push(`  🅒 ${q.options.c}`);
  lines.push(`  🅓 ${q.options.d}`);
  correctAnswers[q.number] = q.correct.toLowerCase();
}

lines.push('');
lines.push('━━━━━━━━━━━━━━━━━━');
lines.push('⏱️ Reply with your answers now!');

// Serialize correct answers: '1:a,2:c,3:b'
const answersString = Object.entries(correctAnswers).map(([n,a]) => `${n}:${a}`).join(',');

return {
  json: {
    phone, senderName, topic, sessionKey, today,
    quizMessage: lines.join('\n'),
    correctAnswers: answersString,
    questionCount: questions.length
  }
};

// Parse Student Answers
// Input: 'answer 1a 2c 3b'
const text = ($json.text || '').trim();
const phone = $json.waId || $json.from || 'unknown';
const senderName = $json.senderName || 'Student';

const answerPart = text.replace(/^answer\s+/i, '').trim();
const matches = answerPart.match(/([1-9][a-dA-D])/g);

if (!matches || matches.length === 0) {
  throw new Error('Could not parse answers. Format: answer 1a 2b 3c');
}

const studentAnswers = {};
for (const match of matches) {
  studentAnswers[parseInt(match[0])] = match[1].toLowerCase();
}

const today = new Date().toISOString().split('T')[0];
const sessionKey = `${phone}_${today}`;

return { json: { phone, senderName, sessionKey, today, studentAnswers } };

// Evaluate Answers & Calculate Score
// Compares student answers vs correct answers from Google Sheets

const parsedData = $('Parse Student Answers').item.json;
const { phone, senderName, sessionKey, today, studentAnswers } = parsedData;

// Find matching quiz row
const allRows = $input.all();
const quizRow = allRows.find(r => r.json.sessionKey === sessionKey);

if (!quizRow) {
  return {
    json: {
      phone,
      feedbackMessage: `⚠️ *No active quiz found!*\n\nYou haven't requested a quiz today yet.\nSend *quiz <topic>* to start one!\nExample: *quiz solar system*`,
      score: 0, total: 0, topic: 'N/A', today, hasQuiz: false
    }
  };
}

const topic = quizRow.json.topic;
const questionCount = parseInt(quizRow.json.questionCount) || 3;

// Parse correct answers from '1:a,2:c,3:b'
const correctAnswers = {};
for (const pair of (quizRow.json.correctAnswers || '').split(',')) {
  const [num, ans] = pair.split(':');
  if (num && ans) correctAnswers[parseInt(num)] = ans.toLowerCase();
}

// Score calculation
let score = 0;
const resultLines = [];
for (let i = 1; i <= questionCount; i++) {
  const studentAns = (studentAnswers[i] || '?').toLowerCase();
  const correctAns = correctAnswers[i] || '?';
  const isCorrect = studentAns === correctAns;
  if (isCorrect) score++;
  resultLines.push(`Q${i}: You answered *${studentAns.toUpperCase()}* ${isCorrect ? '✅' : `❌ (correct: ${correctAns.toUpperCase()})`}`);
}

const percentage = Math.round((score / questionCount) * 100);
let performanceMsg = percentage === 100 ? '🏆 Perfect score! Outstanding!'
  : percentage >= 66 ? '🌟 Great job! Keep it up!'
  : percentage >= 33 ? '📖 Good effort! Review and try again!'
  : '💪 Keep studying! You can do better!';

const feedbackLines = [
  `📝 *Quiz Results – ${topic.toUpperCase()}*`,
  '',
  ...resultLines,
  '',
  '━━━━━━━━━━━━━━━━━━',
  `🎯 *Score: ${score}/${questionCount} (${percentage}%)*`,
  performanceMsg,
  '',
  'Type *progress* to see your full history!',
  'Type *quiz <topic>* to try another quiz!'
];

return {
  json: {
    phone, senderName, topic, score,
    total: questionCount, percentage, sessionKey, today,
    feedbackMessage: feedbackLines.join('\n'),
    hasQuiz: true
  }
};

// Build Progress Report
// Fetches all scores for this student and builds a summary

const phone =  $('Wati Trigger1').first().json.waId|| $('Wati Trigger1').json.from;
const senderName =  $('Wati Trigger1').first().json.senderName|| 'Student';
const allRows = $input.all();
const myRows = allRows.filter(r => String(r.json.phone) === String(phone));

if (myRows.length === 0) {
  return [{ json: {
    phone,
    progressMessage: `📊 *No quiz history yet, ${senderName}!*\n\nStart your first quiz:\n*quiz <topic>*\nExample: *quiz photosynthesis*`
  }}];
}

const totalQuizzes = myRows.length;
const totalScore = myRows.reduce((s, r) => s + (parseFloat(r.json.score) || 0), 0);
const totalQuestions = myRows.reduce((s, r) => s + (parseFloat(r.json.total) || 0), 0);
const avgPercentage = Math.round((totalScore / totalQuestions) * 100);

// Best topic calculation
const topicMap = {};
for (const r of myRows) {
  const t = r.json.topic || 'Unknown';
  if (!topicMap[t]) topicMap[t] = { score: 0, total: 0 };
  topicMap[t].score += parseFloat(r.json.score) || 0;
  topicMap[t].total += parseFloat(r.json.total) || 0;
}
let bestTopic = '';
let bestPct = 0;
for (const [topic, data] of Object.entries(topicMap)) {
  const pct = data.total > 0 ? (data.score / data.total) * 100 : 0;
  if (pct > bestPct) { bestPct = pct; bestTopic = topic; }
}

// Recent 5 quizzes
const recent = myRows.slice(-5).reverse();
const recentLines = recent.map(r => {
  const pct = parseFloat(r.json.percentage) || 0;
  const emoji = pct === 100 ? '🏆' : pct >= 66 ? '🌟' : pct >= 33 ? '📖' : '💪';
  return `${emoji} ${r.json.topic} – ${r.json.score}/${r.json.total} (${pct}%) on ${r.json.date}`;
});

// Progress bar
const filled = Math.round(avgPercentage / 10);
const bar = '█'.repeat(filled) + '░'.repeat(10 - filled);

const lines = [
  `📊 *Progress Report*`,
  `👤 *${senderName}*`,
  '',
  `${bar} *${avgPercentage}% avg score*`,
  '',
  `📝 *Total Quizzes Taken:* ${totalQuizzes}`,
  `✅ *Total Correct:* ${totalScore}/${totalQuestions}`,
  `🏅 *Best Topic:* ${bestTopic} (${Math.round(bestPct)}%)`,
  '',
  '━━━━━━━━━━━━━━━━━━',
  '*Recent Quizzes:*',
  ...recentLines,
  '',
  'Type *quiz <topic>* to keep learning! 🚀'
];

return [{ json: { phone, progressMessage: lines.join('\n') } }];
